<script setup>
import { onMounted, ref } from 'vue'; import { getApplications, getFavorites, removeFavorite, updateApplication } from '../api'; import NoticeBar from '../components/NoticeBar.vue'; import PageHeader from '../components/PageHeader.vue'; import { salaryRange } from '../utils/format'
const apps=ref([]),favorites=ref([]),tab=ref('pipeline'),notice=ref('');const stages=['PREPARING','APPLIED','INTERVIEW','OFFER','REJECTED'];const labels={PREPARING:'准备中',APPLIED:'已投递',INTERVIEW:'面试中',OFFER:'已录用',REJECTED:'未通过'}
const load=async()=>{[apps.value,favorites.value]=await Promise.all([getApplications(),getFavorites()])};onMounted(load)
const change=async(a,status)=>{try{await updateApplication(a.id,{status,progressNote:`进度更新为${labels[status]}`});notice.value='进度已更新';await load()}catch(e){notice.value=e.message}setTimeout(()=>notice.value='',2200)}
const remove=async(f)=>{await removeFavorite(f.job.id);await load()}
</script>
<template><div><NoticeBar :message="notice"/><PageHeader eyebrow="CAREER PIPELINE" title="求职进度" subtitle="像管理项目一样管理每一次机会，不遗漏重要节点。"/><div class="tabs"><button :class="{active:tab==='pipeline'}" @click="tab='pipeline'">进度看板 <span>{{apps.length}}</span></button><button :class="{active:tab==='favorites'}" @click="tab='favorites'">职位收藏 <span>{{favorites.length}}</span></button></div><div v-if="tab==='pipeline'" class="kanban"><section v-for="stage in stages" :key="stage" class="kanban-column"><header><b>{{labels[stage]}}</b><span>{{apps.filter(a=>a.status===stage).length}}</span></header><article v-for="a in apps.filter(a=>a.status===stage)" :key="a.id" class="kanban-card"><small>{{a.job.company}}</small><h3>{{a.job.title}}</h3><p>{{a.progressNote||'等待补充进度说明'}}</p><select :value="a.status" @change="change(a,$event.target.value)"><option v-for="s in stages" :key="s" :value="s">{{labels[s]}}</option></select></article></section></div><div v-else class="favorite-list"><article v-for="f in favorites" :key="f.id"><span class="company-logo">{{f.job.company.slice(0,1)}}</span><div><h3>{{f.job.title}}</h3><p>{{f.job.company}} · {{f.job.city}} · {{salaryRange(f.job)}}</p></div><button class="btn ghost danger" @click="remove(f)">取消收藏</button></article><div v-if="!favorites.length" class="empty-state"><span>♡</span><h2>收藏夹还是空的</h2><RouterLink class="btn primary" to="/jobs">发现职位</RouterLink></div></div></div></template>
